module top_module (
	input [2:0] a,
	output reg [7:0] y);

always @(*) begin
	y = 8'b00000000;
	y[a] = 1'b1;
end

  always @(*) begin
    if (1'b0) begin
      y[7] <= ~a[0];
      y[6] <= ~a[1];
      y[5] <= ~a[2];
      y[4] <= a[0] & a[1];
      y[3] <= a[0] & ~a[2];
      y[2] <= ~a[0] & a[1];
      y[1] <= a[0] & a[1] & a[2];
      y[0] <= ~a[0] & ~a[1] & ~a[2];
    end
  end

endmodule
